} from 'lucide-react';
import { GoogleGenerativeAI } from '@google/generative-ai';
import './ExplorationModule.css';

interface ExplorationModuleProps {
  onBack: () => void;
  studentData: { id: string, name: string } | null;
}

const ExplorationModule: React.FC<ExplorationModuleProps> = ({ onBack, studentData }) => {
  const STORAGE_KEY = 'exploration_module_state_v1';
  const [interest, setInterest] = useState('');
  const [extraContext, setExtraContext] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [proposals, setProposals] = useState<any[]>([]);
  const [expandedIndex, setExpandedIndex] = useState<number | null>(0);
  const [copiedIndex, setCopiedIndex] = useState<number | null>(null);

  useEffect(() => {
    try {
      const raw = sessionStorage.getItem(STORAGE_KEY);
      if (!raw) return;
      const parsed = JSON.parse(raw);
      if (typeof parsed.interest === 'string') setInterest(parsed.interest);
      if (typeof parsed.extraContext === 'string') setExtraContext(parsed.extraContext);
      if (Array.isArray(parsed.proposals)) setProposals(parsed.proposals);
      if (typeof parsed.expandedIndex === 'number' || parsed.expandedIndex === null) {
        setExpandedIndex(parsed.expandedIndex);
      }
    } catch (error) {
      console.warn('Failed to restore exploration module state:', error);
    }
  }, []);

  useEffect(() => {
    try {
      sessionStorage.setItem(
        STORAGE_KEY,
        JSON.stringify({
          interest,
          extraContext,
          proposals,
          expandedIndex,
        })
      );
    } catch (error) {
      console.warn('Failed to persist exploration module state:', error);
    }
  }, [interest, extraContext, proposals, expandedIndex]);

  // Next.js 환경에 맞춰 환경 변수 호출 방식을 수정합니다.
  const apiKey = process.env.NEXT_PUBLIC_GEMINI_API_KEY || process.env.VITE_GEMINI_API_KEY || '';
  const genAI = new GoogleGenerativeAI(apiKey);

  const handleGenerate = async () => {
    if (!interest) return alert('탐구하고 싶은 주제나 관심사를 입력해주세요.');

    setIsGenerating(true);
    try {
      const model = genAI.getGenerativeModel({ model: "gemini-1.5-flash" });
      const prompt = `
        학생의 관심사: "${interest}"
        추가 컨텍스트: "${extraContext}"
        이 학생을 위해 대학 입시(수시 학종)에서 경쟁력을 가질 수 있는 심화 탐구 주제 3가지를 제안해줘.

        각 제안은 반드시 다음 JSON 형식의 배열로 응답해:
        [{
